import{_ as a,c as e,o as t,a2 as r}from"./chunks/framework.CEgrwLex.js";const o="/assets/ll01.B-DGrSZE.png",f=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/getting-started.md","filePath":"zh-CN/guide/getting-started.md","lastUpdated":1723554568000}'),l={name:"zh-CN/guide/getting-started.md"},i=r('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>NapCatQQ V2 正式开始测试，欢迎来到 NapCatQQ (aka 猫猫框架) 的使用文档！</p><h2 id="开始之前" tabindex="-1">开始之前 <a class="header-anchor" href="#开始之前" aria-label="Permalink to &quot;开始之前&quot;">​</a></h2><p>在开始使用之前，你需要了解以下内容。</p><details class="details custom-block"><summary>猫猫框架的原理是什么，能够做些什么？</summary><p>猫猫框架通过魔法的手段获得了 QQ 的发送消息、接收消息等接口，为了方便使用，猫猫框架将通过一种名为 <a href="https://11.onebot.dev" target="_blank" rel="noreferrer">OneBot</a> 的约定将你的 HTTP / WebSocket 请求按照规范读取，再去调用猫猫框架所获得的QQ发送接口之类的接口。</p></details><p>现在，前往 <a href="https://github.com/NapNeko/NapCatQQ/releases" target="_blank" rel="noreferrer">NapCatQQ 的 release 页面</a>，各位可以看到有两个压缩包，文件名后缀分别为 <code>Shell</code> 和 <code>Framework</code>，应当如何选择呢？这就需要了解猫猫框架的启动方式了。</p><ol><li><p>作为 <a href="https://liteloaderqqnt.github.io/" target="_blank" rel="noreferrer">LiteLoaderQQNT</a> 插件运行，类似 <a href="https://llonebot.github.io" target="_blank" rel="noreferrer">LLOneBot</a>，可以实现“人机合一”。</p></li><li><p>通过命令行启动，当你不需要或没有图形化界面，或者内存紧张，可以使用此方法。</p></li><li><p>“Only GUI” 模式，当你不想使用 LiteLoader 插件时，却又想人机合一，又想折腾时，可以考虑此方法。</p></li></ol><p>方法 1 和 3 都是“有头启动”，应当使用 Framework 版本；方法 2 是无头启动，应当使用 Shell 版本。我们目前对方法 1 和 2 有较为完整的文档支持，方法 3 还请自行探索。</p><h2 id="作为-liteloader-插件启动" tabindex="-1">作为 LiteLoader 插件启动 <a class="header-anchor" href="#作为-liteloader-插件启动" aria-label="Permalink to &quot;作为 LiteLoader 插件启动&quot;">​</a></h2><ol><li><p>按照 <a href="https://liteloaderqqnt.github.io/" target="_blank" rel="noreferrer">LiteLoaderQQNT 官网</a>的指导安装 LiteLoaderQQNT 框架。</p></li><li><p>在 LiteLoaderQQNT 的设置页面（如下图）将 <code>NapCat.Framework.zip</code> 导入即可。 <img src="'+o+'" alt="在这里"></p></li></ol><h2 id="通过命令行启动" tabindex="-1">通过命令行启动 <a class="header-anchor" href="#通过命令行启动" aria-label="Permalink to &quot;通过命令行启动&quot;">​</a></h2><h3 id="一键撸猫" tabindex="-1">一键撸猫 <a class="header-anchor" href="#一键撸猫" aria-label="Permalink to &quot;一键撸猫&quot;">​</a></h3><details class="details custom-block"><summary>Linux 一键脚本(支持Ubuntu 20+/Debian 10+, Centos系仅支持9)</summary><p><code>curl -o napcat.sh https://nclatest.znin.net/NapNeko/NapCat-Installer/main/script/install.sh &amp;&amp; sudo bash napcat.sh</code></p></details><details class="details custom-block"><summary><a href="https://github.com/NapNeko/NapCat-Docker" target="_blank" rel="noreferrer">Linux Docker</a></summary><p><a href="https://github.com/NapNeko/NapCat-Docker" target="_blank" rel="noreferrer">使用 NapCat-Docker</a></p></details><h3 id="手动撸猫" tabindex="-1">手动撸猫 <a class="header-anchor" href="#手动撸猫" aria-label="Permalink to &quot;手动撸猫&quot;">​</a></h3><p>目前已经研究完成并公布的启动方式有 BootWay03 和 05。</p><p><a href="./boot/shell/BootWay05">前往了解 BootWay05</a>（仅支持 Windows x64）</p><p><a href="./boot/shell/BootWay03">前往了解 BootWay03</a>（支持 Windows 和 Linux）</p><h2 id="only-gui" tabindex="-1">Only GUI <a class="header-anchor" href="#only-gui" aria-label="Permalink to &quot;Only GUI&quot;">​</a></h2><p>目前该方案没有完整支持，仅有<a href="./boot/only-gui/BootWay03">手动方案</a>，与上面的 BootWay03 类似。</p><h2 id="启动之后" tabindex="-1">启动之后 <a class="header-anchor" href="#启动之后" aria-label="Permalink to &quot;启动之后&quot;">​</a></h2><p>恭喜你，如果看到这里，你已经成功启动了它，可以尝试阅读下面的进阶说明！</p><p><a href="./config/basic">如何进行 NapCat 的基础设置</a></p><p><a href="./faq">如何配置 NapCat 的语音发送</a> 参考 <code>语音、视频发送失败</code> 发生失败条目</p><p><a href="./faq">遇到 NapCat 崩溃问题如何解决</a></p>',25),s=[i];function n(h,p,d,c,u,m){return t(),e("div",null,s)}const _=a(l,[["render",n]]);export{f as __pageData,_ as default};
